\begin{lemma}\label{lem:rankclaim}
    For \(\MZero=[1\;\;0]\), any positive integer \(p\), and reals
    \(0<x,y\le 1\) satisfying \(p+\log y>0\), one has
    \[
        \comp{\bracket{\MZero}{p}{x}{y}}
        \ge
        \ceil{\log\!\bigl(p+\log y\bigr)}+1.
    \]
\end{lemma}

\begin{definition}[$(\delta,b)$-robust matrix]\label{def:robust}
    Let \(b\ge 0\) be real and let
    \(\delta\in\bigl(0,\tfrac12\bigr)\).
    A Boolean matrix \(M\) is \emph{$(\delta,b)$-robust} if
    \begin{align}
        \comp{M} &\ge 1,
        \tag{R1}\label{eq:robust-r1}\\
        \comp{\bracket{M}{1}{2^{-b}}{\tfrac12+\delta}}
        &\ge \comp{M},
        \tag{R2}\label{eq:robust-r2}\\
        \comp{\bracket{M}{1}{2^{-b}}{\tfrac18+\tfrac{\delta}{4}}}
        &\ge \comp{M}-2,
        \tag{R3}\label{eq:robust-r3}\\
        \comp{\bracket{M}{1}{2^{-b}}{\tfrac14+\tfrac{\delta}{2}}}
        &\ge \comp{M}-1.
        \tag{R4}\label{eq:robust-r4}
    \end{align}
\end{definition}

\begin{lemma}\label{lem:two-copy-ladder}
    Let \(M\) be a Boolean matrix, let \(0<x\le \tfrac12\), let \(0<y\le 1\),
    and let \(H\in \mathbb R\).  Assume
    \[
        \comp{\bracket{M}{1}{x}{\frac{y}{4}}} \ge H-2,
        \qquad
        \comp{\bracket{M}{1}{x}{\frac{y}{2}}} \ge H-1,
        \qquad
        \comp{\bracket{M}{1}{x}{y}} \ge H.
    \]
    Then
    \begin{align*}
        \comp{\bracket{M}{2}{2x}{\frac{y^2}{4}}}
        &\ge H-1,\\
        \comp{\bracket{M}{2}{2x}{\frac{y^2}{2}}}
        &\ge H,\\
        \comp{\bracket{M}{2}{2x}{y^2}}
        &\ge H+1.
    \end{align*}
\end{lemma}

\begin{lemma}[One-step partition]\label{lem:partition}
    Let \(M\) be a Boolean matrix, let \(p\ge 1\), let
    \(\sigma\in\{0,1\}\), let \(0<x\le \frac12\), and let \(0<y\le 1\).
    If
    \[
        \comp{\bracket{M}{2p+\sigma}{2x}{y}}\ge 1,
    \]
    then
\begin{equation}\label{eq:partition-raw}
        \begin{aligned}
            \comp{\bracket{M}{2p+\sigma}{2x}{y}}
            \ge
            1+\min\Biggl(
                &\comp{\bracket{M}{2p+\sigma}{x}{y}},\\
                &\min_{\substack{0\le \ell < p\\ a\in[0,1]}}
                \max\Bigl(
                    \comp{\bracket{M}{p+\ell+\sigma}{x}{y^a}},
                    \comp{\bracket{M}{p-\ell}{x}{y^{1-a}}}
                \Bigr),\\
                &\comp{\bracket{M}{2p+\sigma}{2x}{y/2}}
            \Biggr).
        \end{aligned}
    \end{equation}
\end{lemma}

\begin{corollary}\label{cor:robust-two-copy-ladder}
    Let \(M\) be \robust, assume in addition that \(b\ge 1\), and write
    \[
        y:=\tfrac12+\delta.
    \]
    Then
    \begin{align*}
        \comp{\bracket{M}{2}{2^{-b+1}}{\frac{y^2}{4}}}
        &\ge \comp{M}-1,\\
        \comp{\bracket{M}{2}{2^{-b+1}}{\frac{y^2}{2}}}
        &\ge \comp{M},\\
        \comp{\bracket{M}{2}{2^{-b+1}}{y^2}}
        &\ge \comp{M}+1.
    \end{align*}
\end{corollary}

\begin{corollary}\label{cor:two-copy-amplification}
    Let \(M\) be \robust, and assume in addition that \(b\ge 1\).  Then
    \[
        \comp{\bracket{M}{2}{2^{-b+1}}{\bigl(\tfrac12+\delta\bigr)^2}}
        \ge
        \comp{M}+1.
    \]
\end{corollary}

\begin{corollary}\label{cor:plus-one-family}
    Let \(M\) be \robust, and assume \(\comp{M}\ge 2\).  Then for every
    integer \(k\) with \(2\le k\le b\),
    \[
        \comp{\bracket{M}{2^{k-1}+1}{2^{k-b}}{\bigl(\tfrac12+\delta\bigr)^2}}
        \ge
        \comp{M}+k.
    \]
\end{corollary}

\begin{corollary}[Power-of-two lower bound]\label{cor:power-of-two}
    Let \(M\) be \robust with \(b\ge 1\), assume \(\comp{M}\ge 2\), and write
    \(y_0:=(\tfrac12+\delta)^2\).  If \(u\ge 2\) is a power of two with
    \(u\le 2^b\), then
    \[
        \comp{\bracket{M}{u}{u2^{-b}}{y_0}}
        \ge
        \comp{M}+\log u.
    \]
\end{corollary}

\begin{lemma}\label{lem:hard-seed}
    Fix an integer \(j\ge 2\).  Then for all sufficiently large powers of two
    \(t\), the following implication holds: if \(M\) is \robust with
    \(\comp{M}\ge 3\) and \(t\le 2^b\), then
    \[
        \comp{\bracket{M}
        {\dfrac{(2^{j-1}+2)t}{2^j}}
        {2^{-b}t}
        {2^{-\,2^{0.49\sqrt{\log t}}}}}
        \ge
        \comp{M}+\log t.
    \]
\end{lemma}

\DefineProblemNoPara{$\{0,1\}$-$d$-\textsc{Dimension Vector Bin Packing}}{A set of $n$ vectors $\{v_1,\ldots,v_n\}\subseteq\{0,1\}^{d}$, a capacity parameter $c$, and a number of bins $m$ (where $m$ is a power of two).}{Does there exist a partition of the vectors into $m$ bins such that every bin $B_i$ satisfies
$\lVert \sum_{v\in B_i} v\rVert_{\infty}\le c$\,?}

In the reduction we only use the case \(c=1\) and \(m=4\).

\begin{lemma}[Transpose symmetry]\label{lem:transposeComp}
    For every Boolean matrix \(M\),
    \[
        \comp{\transpose{M}}=\comp{M}.
    \]
\end{lemma}

\begin{lemma}\label{lem:M1-robust}
    \(\transpose{\MOne}\) is \((\delta,\Robustness_1)\)-robust.
\end{lemma}

\begin{lemma}
    \label{lem:M1TerminalStage2}
    Let
    \[
        y^{\mathrm{term}}_2
        :=
        \left(
        \frac{h_2\,2^{-(\log q_2+\comp{\MOne})}}
             {1+\eps_{q_2,\Independence_2}}
        \right)^{1/\Independence_2}.
    \]
    Then
    \[
        \comp{\bracket{\MOne}{1}{y^{\mathrm{term}}_2}{2^{-\Robustness_1}}}
        \ge
        \comp{\MOne}-\log r_1.
    \]
\end{lemma}

\begin{corollary}\label{cor:M2-complexity}
    \[
        \comp{\MTwo}
        =
        \comp{\MOne}+\ceil{\log q_2}
        =
        B_{\mathrm{cap}}+\ceil{\log q_2}.
    \]
\end{corollary}

\begin{lemma}\label{lem:M2-robust}
    \(\transpose{\MTwo}\) is \((\delta,\Robustness_2)\)-robust.
\end{lemma}

\begin{lemma}[Polynomial-time constructibility]\label{lem:polytime}
    The matrix \(\MFour\) has polynomial size and can be constructed in
    polynomial time from the source instance.
\end{lemma}

\begin{theorem}[NP-completeness of communication complexity]
    \label{thm:main-nphard-intro}
    Given the truth table of a Boolean function
    $f:\{0,1\}^n\times\{0,1\}^n\to\{0,1\}$ and an integer $k$ in binary,
    deciding whether $\comp{f}\le k$ is \textsf{NP}-complete.
\end{theorem}

